const staticData = $getWorkflowStaticData('global');
if (!staticData.notificados) staticData.notificados = {};

const { pedidos } = $('Obtener Pedidos').item.json;

const hoy = new Date();
hoy.setHours(0, 0, 0, 0);
const hoyStr = hoy.toISOString().slice(0, 10);

// Filtrar pedidos que vencen en 1 o 2 dias
const proximos = pedidos.filter(p => {
  if (!p.fechaEntrega) return false;
  if (p.estado === 'enviado-final') return false;
  const fecha = new Date(p.fechaEntrega + 'T00:00:00');
  const diff = Math.round((fecha - hoy) / 86400000);
  return diff === 1 || diff === 2;
}).map(p => {
  const fecha = new Date(p.fechaEntrega + 'T00:00:00');
  const diff = Math.round((fecha - hoy) / 86400000);
  return { ...p, diasRestantes: diff };
});

// Solo notificar si no fue notificado hoy (permite re-notificar al día siguiente cuando quedan 1 día)
const nuevos = proximos.filter(p => staticData.notificados[p.id] !== hoyStr);

if (nuevos.length === 0) return [];

// Registrar con la fecha de hoy
for (const p of nuevos) staticData.notificados[p.id] = hoyStr;

// Limpiar los que ya se entregaron
const idsActivos = pedidos.filter(p => p.estado !== 'enviado-final').map(p => p.id);
for (const id of Object.keys(staticData.notificados)) {
  if (!idsActivos.includes(Number(id))) delete staticData.notificados[id];
}

return nuevos.map(p => ({ json: p }));

